export const DEFAULT_TICKET_DRAFT_RESEARCH_LIMITS: TicketDraftResearchLimits = {
  maxResearchMs: 10_000,
  maxUrls: 3,
  maxUrlFetchMs: 4_000,
  maxUrlContentChars: 8_000,
